import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';

export default function VerificationScreen() {
  const [code, setCode]         = useState(['', '', '', '']);
  const [timer, setTimer]       = useState(60);
  const [canResend, setCanResend] = useState(false);
  const [error, setError]       = useState('');
  const inputs = useRef([]);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  useEffect(() => {
    if (!auth.phone) navigate('/login');
  }, []);

  useEffect(() => {
    if (timer <= 0) { setCanResend(true); return; }
    const id = setInterval(() => setTimer(t => t - 1), 1000);
    return () => clearInterval(id);
  }, [timer]);

  const handleChange = (idx, val) => {
    if (!/^\d?$/.test(val)) return;
    const next = [...code];
    next[idx] = val;
    setCode(next);
    if (val && idx < 3) inputs.current[idx + 1]?.focus();
  };

  const handleKeyDown = (idx, e) => {
    if (e.key === 'Backspace' && !code[idx] && idx > 0) {
      inputs.current[idx - 1]?.focus();
    }
  };

  const handleVerify = () => {
    if (code.join('').length < 4) { setError('הכנס 4 ספרות'); return; }
    // Mock: any 4-digit code is accepted
    localStorage.setItem('pizzaAuth', JSON.stringify({ ...auth, verified: true }));
    navigate('/');
  };

  const handleResend = () => {
    setTimer(60);
    setCanResend(false);
    setCode(['', '', '', '']);
    setError('');
    inputs.current[0]?.focus();
  };

  const filled = code.filter(Boolean).length;

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50">

      {/* Navy Hero */}
      <div
        className="px-5 pt-14 pb-16 text-center"
        style={{ background: 'linear-gradient(160deg, #006491 0%, #004d6e 100%)' }}
      >
        <div className="text-6xl mb-3">📱</div>
        <h1 className="text-white font-black text-2xl mb-1">אימות מספר</h1>
        <p className="text-blue-200 text-sm">נשלח אליך קוד בן 4 ספרות</p>
        {auth.phone && (
          <p className="text-white font-black text-lg mt-2" dir="ltr">{auth.phone}</p>
        )}
      </div>

      {/* Card */}
      <div className="px-4 -mt-6">
        <div className="bg-white rounded-2xl shadow-xl p-6">
          <p className="text-center text-gray-500 text-sm mb-6">
            הכנס את הקוד שקיבלת ב-SMS
          </p>

          {/* Code Inputs */}
          <div className="flex gap-3 justify-center mb-2" dir="ltr">
            {code.map((digit, idx) => (
              <input
                key={idx}
                ref={el => (inputs.current[idx] = el)}
                type="text"
                inputMode="numeric"
                maxLength={1}
                value={digit}
                onChange={e => handleChange(idx, e.target.value)}
                onKeyDown={e => handleKeyDown(idx, e)}
                className={`w-16 h-16 text-center text-3xl font-black border-2 rounded-2xl focus:outline-none transition ${
                  digit
                    ? 'border-tomato bg-red-50 text-tomato'
                    : 'border-gray-200 bg-gray-50 text-gray-800 focus:border-tomato'
                }`}
              />
            ))}
          </div>

          {error && <p className="text-center text-red-500 text-sm mb-3 font-medium">{error}</p>}

          {/* Progress dots */}
          <div className="flex justify-center gap-2 mb-6 mt-3">
            {code.map((d, i) => (
              <div
                key={i}
                className={`w-2 h-2 rounded-full transition-all duration-200 ${
                  d ? 'bg-tomato scale-125' : 'bg-gray-200'
                }`}
              />
            ))}
          </div>

          <button
            onClick={handleVerify}
            disabled={filled < 4}
            className="w-full bg-tomato text-white py-4 rounded-2xl font-black text-lg shadow-md hover:bg-red-700 transition active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed mb-4"
          >
            אמת קוד ✓
          </button>

          <p className="text-center text-sm text-gray-500">
            {canResend ? (
              <button
                onClick={handleResend}
                className="text-navy font-black hover:underline"
              >
                שלח קוד מחדש
              </button>
            ) : (
              <>שלח שוב בעוד <span className="font-black text-tomato">{timer}</span> שניות</>
            )}
          </p>
        </div>

        <button
          onClick={() => navigate('/login')}
          className="mt-4 w-full text-center text-sm text-gray-400 py-3 hover:text-gray-600 transition"
        >
          ← שנה מספר טלפון
        </button>
      </div>
    </div>
  );
}
